            "إعلان بالسند التنفيذي",
            "إفادة استعلام بنوك",
            "تقديم طلبات الاستعلام",
            "تم غلق الملف",
            "تم قيد الإشكال",
            "اجتماع خبرة",
            "اعتماد الصيغة التنفيذية",
            "تم قيد الدعوى",
            "تم الاخلاء",
            "إرسال إلى الترجمة",
            "إنتظار الموافقة علي قيد الشيك",
            "تم قيد الشيك",
            "تمت الموافقة على قيد الشيك",
