  useEffect(() => {
    fetchActionTypes();
  }, []);

  useEffect(() => {
    if (caseDetails?.admin_id && userMetadata.length > 0) {
      // 1. Determine Firm Admin ID first
      let firmAdminId = caseDetails.admin_id;
      const creator = userMetadata.find(
        (u) =>
          u.user_id === caseDetails.admin_id ||
          u.new_lawyer_id === caseDetails.admin_id
      );

      if (creator?.admin_user_id) {
        firmAdminId = creator.admin_user_id;
      }

      // 2. Filter all metadata rows for matching firm
      const cat1Members = userMetadata.filter(
        (u) =>
          (u.admin_user_id === firmAdminId || u.user_id === firmAdminId) &&
          u.role === "الفئة 1"
      );
      setFirmCategory1Lawyers(cat1Members);
    }
  }, [caseDetails?.admin_id, userMetadata]);

  // Fetch case details when caseId is available from URL
  useEffect(() => {
    const loadCaseDetails = async () => {
      if (!router.isReady || (!caseId && !caseNumber)) {
        return;
      }

      try {
        setLoading(true);

        const queryColumn = caseId ? "id" : "case_number";
        const queryValue = caseId || caseNumber;

        // Fetch case data
        const { data, error } = await supabase
          .from("cases")
          .select("*")
          .eq(queryColumn, queryValue)
          .single();

        if (error) {
          console.error("Error fetching case details:", error);
          setLoading(false);
          setIsCalendarTransition(false); // Safety clear
          return;
        }

        if (data) {
          setCaseDetails(data);
          setLoading(false);
          setMinLoadFinished(true);
        }
      } catch (error) {
        console.error("Error loading case:", error);
        setLoading(false);
        setIsCalendarTransition(false); // Safety clear
      }
    };

    loadCaseDetails();
  }, [router.isReady, caseId, caseNumber]);

  // Handle tab query parameter from URL
  useEffect(() => {
    if (router.query.tab && router.isReady && (caseId || caseNumber)) {
      const tab = router.query.tab;

      // Handle 'jobTasks' tab
      if (tab === "jobTasks") {
        setActiveView("jobTasks");
        setHighlightedButton("jobTasks");
        // Delay fetchTasks slightly to ensure component is ready
        setTimeout(async () => {
          await fetchTasks();

          // Handle Highlighting if requested
          const highlightType = router.query.highlightType;
          const highlightId = router.query.highlightId;

          if (highlightType === "task" && highlightId) {
            setHighlightedTaskId(parseInt(highlightId));

            // Scroll after render (tasks might take a moment to appear)
            setTimeout(() => {
              const element =
                document.querySelector(`[data-task-id="${highlightId}"]`) ||
                document.getElementById(`task-${highlightId}`);
              if (element) {
                element.scrollIntoView({ behavior: "smooth", block: "center" });
                // Optional: Clear highlight after a few seconds
                setTimeout(() => setHighlightedTaskId(null), 5000);
              }
            }, 800); // Slightly longer delay for tasks
          }
        }, 100);
      }
      // Handle 'sessions' tab
      else if (tab === "sessions") {
        setActiveView("sessions");
        setHighlightedButton("sessions");

        const highlightType = router.query.highlightType;
        const highlightId = router.query.highlightId;
        if (highlightType === "session" && highlightId) {
          setIsCalendarTransition(true);
        }

        setTimeout(() => {
          const fetchSessions = async () => {
            try {
              // Try to get case_number from caseDetails if available, otherwise use caseNumber
              // We should wait until caseDetails is loaded securely if we only have an ID
              if (!caseDetails && caseId && !caseNumber) {
                return; // Wait for caseDetails to load so we don't query sessions with just an integer ID
              }
              const caseNumberToUse =
                caseDetails?.case_number || caseNumber || caseId;

              const user = supabase.auth.user();
              if (!user) return;

              // Check user role
              const { data: userMeta } = await supabase
                .from("user_metadata")
                .select("admin_user_id, role")
                .eq("user_id", user.id)
                .single();

              let sessionQuery = supabase
                .from("sessions")
                .select("*")
                .eq("case_number", caseNumberToUse)
                .order("sessiondate", { ascending: false });

              // No extra user restriction - if they can see the case, they can see its sessions

              const [{ data: sessions, error }, { data: attachments }] =
                await Promise.all([
                  sessionQuery,
                  supabase
                    .from("attachments")
                    .select("*")
                    .eq("case_number", caseNumberToUse),
                ]);

              if (!error && sessions) {
                // 2. Determine Case Admin ID (The Firm Owner)
                let thisCaseAdminId = caseDetails?.admin_id;

                // If we don't have the admin_id from props, fetch it using the unique case ID or number
                if (!thisCaseAdminId && (caseId || caseNumber)) {
                  const { data: cData } = await supabase
                    .from("cases")
                    .select("admin_id")
                    .eq(
                      caseId && !isNaN(caseId) ? "id" : "case_number",
                      caseId || caseNumber,
                    )
                    .single();
                  thisCaseAdminId = cData?.admin_id;
                }

                // 3. Fetch Firm User IDs (Admin + all Lawyers under this admin)
                let firmUserIds = [thisCaseAdminId];
                try {
                  const { data: firmLawyers } = await supabase
                    .from("user_metadata")
                    .select("user_id")
                    .eq("admin_user_id", thisCaseAdminId);

                  if (firmLawyers) {
                    firmUserIds = [
                      ...new Set([
                        thisCaseAdminId,
                        ...firmLawyers.map((l) => l.user_id),
                      ]),
                    ].filter(Boolean);
                  }
                } catch (err) {
                  console.error("Error fetching firm lawyers:", err);
                }

                // 4. Fetch Creator Metadata for the sessions we found
                const creatorUserIds = [
                  ...new Set(
                    (sessions || []).map((s) => s.user_id).filter(Boolean),
                  ),
                ];
                let userMetadataList = [];

                if (creatorUserIds.length > 0) {
                  try {
                    const { data } = await supabase
                      .from("user_metadata")
                      .select("user_id, admin_user_id, new_lawyer_id, username")
                      .or(
                        `user_id.in.(${creatorUserIds.join(",")}),new_lawyer_id.in.(${creatorUserIds.join(",")})`,
                      ); // Filter!
                    userMetadataList = data || [];
                  } catch (err) {
                    console.error("Error fetching user metadata:", err);
                  }
                }

                // 5. Enrich session data with user names
                const enrichedSessions = sessions.map((session) => {
                  // Prioritize direct Auth ID matching
                  // Only match the user's own metadata row
                  // 1. Try to match by new_lawyer_id first (for lawyers)
                  // 2. Then match by user_id, BUT exclude records that have a new_lawyer_id (to avoid picking a lawyer record when we want the admin)
                  const creator =
                    userMetadataList.find(
                      (u) => u.new_lawyer_id === session.user_id,
                    ) ||
                    userMetadataList.find(
                      (u) => u.user_id === session.user_id && !u.new_lawyer_id,
                    );
                  // Do NOT match against admin_user_id, as that returns a subordinate's row for an admin's action
                  return {
                    ...session,
                    user_name:
                      session.user_name || creator?.username || "مستخدم",
                    folderAttachments: (attachments || []).filter(
                      (att) => att.session_id === session.id,
                    ),
                  };
                });

                setSessionData(enrichedSessions || []);

                // Handle Session Highlighting if requested
                const highlightType = router.query.highlightType;
                const highlightId = router.query.highlightId;

                if (highlightType === "session" && highlightId) {
                  const numericHighlightId = parseInt(highlightId);
                  setHighlightedSessionId(numericHighlightId);

                  // Function to scroll and highlight with retry
                  const scrollToSession = (retryCount = 0) => {
                    const element =
                      document.getElementById(`session-${highlightId}`) ||
                      document.querySelector(
                        `[data-session-id="${highlightId}"]`,
                      );
                    if (element) {
                      element.scrollIntoView({
                        behavior: "smooth",
                        block: "center",
                      });
                      // Re-apply highlight just in case
                      setHighlightedSessionId(parseInt(highlightId));

                      // Clear transition after scroll
                      setTimeout(() => setIsCalendarTransition(false), 500);

                      // Clear highlight after delay
                      setTimeout(() => setHighlightedSessionId(null), 5000);
                    } else if (retryCount < 3) {
                      // Retry after another delay if element not found
                      setTimeout(() => scrollToSession(retryCount + 1), 500);
                    } else {
                      // Failed, clear transition anyway
                      setIsCalendarTransition(false);
                    }
                  };

                  // Wait for DOM to update after state change
                  setTimeout(scrollToSession, 800);

                  // Safety timeout to clear loading if anything goes wrong
                  setTimeout(() => setIsCalendarTransition(false), 4000);
                }
              }
            } catch (error) {
              console.error("Error fetching sessions:", error);
              setIsCalendarTransition(false);
            }
          };
          fetchSessions();
        }, 100);
      }
      // Handle 'reminders' tab (implicitly or explicitly)
      else if (tab === "reminders") {
        setActiveView("reminders");
        setHighlightedButton("reminders");

        // Check if there's a reminder_id in the URL to highlight
        const reminderId = router.query.reminderId;
        if (reminderId) {
          setIsCalendarTransition(true);
        }

        setTimeout(() => {
          if (caseDetails?.case_number) {
            fetchRemindersForCase();
          } else if (!caseId && !caseNumber) {
            // Only fetch general reminders if we're not waiting for a specific case to load
            fetchReminders();
          }

          if (reminderId) {
            const reminderIdStr = String(reminderId);
            // Wait for reminders to load, then highlight
            setTimeout(() => {
              const findAndHighlight = () => {
                const escapedId = CSS.escape(reminderIdStr);
                let reminderElement = document.querySelector(
                  `[data-reminder-id="${escapedId}"]`,
                );
                if (!reminderElement)
                  reminderElement = document.querySelector(
                    `[data-reminder-id='${escapedId}']`,
                  );
                if (!reminderElement) {
                  const allReminders =
                    document.querySelectorAll("[data-reminder-id]");
                  for (let i = 0; i < allReminders.length; i++) {
                    if (
                      allReminders[i].getAttribute("data-reminder-id") ===
                      reminderIdStr
                    ) {
                      reminderElement = allReminders[i];
                      break;
                    }
                  }
                }

                if (reminderElement) {
                  setHighlightedReminderId(reminderIdStr);
                  setTimeout(() => {
                    reminderElement.scrollIntoView({
                      behavior: "smooth",
                      block: "center",
                    });
                    // Clear transition loading after scrolling
                    setTimeout(() => setIsCalendarTransition(false), 500);
                  }, 100);
                  return true;
                }
                return false;
              };

              if (!findAndHighlight()) {
                setTimeout(() => {
                  if (!findAndHighlight()) {
                    setTimeout(() => {
                      if (!findAndHighlight()) setIsCalendarTransition(false); // Safety clear
                    }, 500);
                  }
                }, 300);
              }
              setTimeout(() => setHighlightedReminderId(null), 5000);
            }, 500);

            // Safety timeout to clear loading if anything goes wrong
            setTimeout(() => setIsCalendarTransition(false), 4000);
          }
        }, 100);
      }
    }
  }, [router.query, router.isReady, caseId, caseDetails]); // Updated dependencies

