  const handleFeeSubmit = async (e) => {
    e.preventDefault();

    // 1. Get Current Authenticated User
    const currentUser = supabase.auth.user();
    if (!currentUser) {
      console.error("No authenticated user found. Please log in.");
      alert("خطأ في المصادقة. يرجى تسجيل الدخول مرة أخرى.");
      if (typeof setIsSubmittingFee === "function") setIsSubmittingFee(false);
      return;
    }

    // 2. Ensure caseId is available
    if (!caseId) {
      console.error("Case ID is missing. Cannot save fee.");
      alert("خطأ: معرف القضية مفقود.");
      if (typeof setIsSubmittingFee === "function") setIsSubmittingFee(false);
      return;
    }

    if (typeof setIsSubmittingFee === "function") setIsSubmittingFee(true);

    let fetchedAdminIdFromMetadata = null;
    let fetchedLawyerIdFromMetadata = null;

    try {
      // 3. Get admin_id and new_lawyer_id from user_metadata based on the logged-in user's ID
      console.log(
        "Fetching user_metadata for logged-in user ID:",
        currentUser.id,
      );
      const { data: userDataArray, error: userError } = await supabase
        .from("user_metadata")
        .select("admin_user_id, new_lawyer_id") // Select the IDs you need
        .or(
          `admin_user_id.eq."${currentUser.id}",new_lawyer_id.eq."${currentUser.id}",user_id.eq."${currentUser.id}"`,
        )
        .limit(1);

      if (userError) {
        console.error(
          "Error fetching user_metadata for logged-in user:",
          currentUser.id,
          ". Details:",
          userError.message,
        );
        alert(
          `خطأ في جلب بيانات المستخدم/المحامي من السجل التعريفي: ${userError.message}. تأكد من وجود سجل واحد مطابق للمستخدم الحالي.`,
        );
        if (typeof setIsSubmittingFee === "function") setIsSubmittingFee(false);
        return;
      }

      const userData =
        userDataArray && userDataArray.length > 0 ? userDataArray[0] : null;

      if (!userData) {
        console.error(
          "No user_metadata found for logged-in user ID:",
          currentUser.id,
        );
        alert(`لم يتم العثور على بيانات تعريفية للمستخدم الحالي.`);
        if (typeof setIsSubmittingFee === "function") setIsSubmittingFee(false);
        return;
      }

      // Assuming userData contains the admin_id and new_lawyer_id for the logged-in user's context
      fetchedAdminIdFromMetadata = userData.admin_user_id;
      fetchedLawyerIdFromMetadata = userData.new_lawyer_id;

      // It's possible that userData.admin_user_id IS currentUser.id.
      // And userData.new_lawyer_id is the specific lawyer ID associated with this user/admin record.
      console.log(
        "Fetched admin_id from metadata:",
        fetchedAdminIdFromMetadata,
        "Fetched lawyer_id from metadata:",
        fetchedLawyerIdFromMetadata,
      );

      // 4. Handle File Uploads to Supabase Storage
      let uploadedAttachmentUrls = [];
      if (feeFormData.attachments && feeFormData.attachments.length > 0) {
        console.log(
          `Uploading ${feeFormData.attachments.length} attachment(s)...`,
        );
        for (const file of feeFormData.attachments) {
          const filePathInBucket = `${caseId}/fee_attachments/${Date.now()}_${file.name.replace(/\s+/g, "_")}`;

          // Get file extension and determine content-type
          const fileExtension = file.name.split(".").pop()?.toLowerCase() || "";
          const getContentType = (ext) => {
            const mimeTypes = {
              doc: "application/msword",
              docx: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
              xls: "application/vnd.ms-excel",
              xlsx: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
              pdf: "application/pdf",
              jpg: "image/jpeg",
              jpeg: "image/jpeg",
              png: "image/png",
              gif: "image/gif",
              webp: "image/webp",
              txt: "text/plain",
              rtf: "application/rtf",
            };
            return mimeTypes[ext] || file.type || "application/octet-stream";
          };

          const { error: uploadError } = await supabase.storage
            .from("images")
            .upload(filePathInBucket, file, {
              cacheControl: "3600",
              upsert: false,
              contentType: getContentType(fileExtension),
            });

          if (uploadError) {
            console.error("Error uploading file:", uploadError.message);
            throw new Error(
              `فشل في تحميل الملف ${file.name}: ${uploadError.message}`,
            );
          }

          // Use the same pattern as handleSubmitExpenses (lines 1732-1738)
          // Use the filePathInBucket directly, not uploadData.path
          const { publicURL: filePublicURL } = await supabase.storage
            .from("images")
            .getPublicUrl(filePathInBucket);

          if (!filePublicURL) {
            console.error("Error getting public URL for attachment");
            throw new Error(`Failed to get public URL for file ${file.name}.`);
          }

          uploadedAttachmentUrls.push(filePublicURL);
        }
      }

      // 5. Prepare Data for 'lawyer_fees' Table
      const feeDataToInsert = {
        case_id: caseId,
        payment_date: feeFormData.payment_date,
        payment_amount: parseFloat(feeFormData.payment_amount) || 0,
        payment_details: feeFormData.payment_details,
        currency: caseDetails?.currency || feeFormData.currency || "USD", // Use currency from case, fallback to form data or default
        attachments:
          uploadedAttachmentUrls.length > 0 ? uploadedAttachmentUrls : null,
        admin_id: fetchedAdminIdFromMetadata, // ID from user_metadata
        lawyer_id: fetchedLawyerIdFromMetadata, // ID from user_metadata
        created_at: new Date().toISOString(), // Store creation timestamp
      };

      console.log("Data to insert into lawyer_fees:", feeDataToInsert);

      // 6. Insert Data into 'lawyer_fees' Table
      const { data: insertedData, error: insertError } = await supabase
        .from("lawyer_fees")
        .insert([feeDataToInsert])
        .select();

      if (insertError) {
        console.error(
          "Supabase database insert error for lawyer_fees:",
          insertError.message,
          insertError.details,
          insertError.hint,
        );
        throw new Error(`فشل في حفظ بيانات السداد: ${insertError.message}`);
      }

      console.log("Fee data inserted successfully:", insertedData);

      // 7. Handle Success - Update UI
      if (insertedData && insertedData.length > 0) {
        const newFeeId = insertedData[0].id;

        // Close modal first
        if (typeof handleCloseAddFeeModal === "function")
          handleCloseAddFeeModal();

        // Switch to lawyerFees view
        setActiveView("lawyerFees");
        setHighlightedButton("lawyerFees");

        // Refresh data
        if (typeof fetchLawyerFees === "function") {
          await fetchLawyerFees(caseId);
        }

        // Scroll and highlight new entry - similar to reminder highlighting
        setTimeout(() => {
          const feeElement =
            document.querySelector(`[data-lawyer-fee-id="${newFeeId}"]`) ||
            document.getElementById(`lawyer-fee-${newFeeId}`);
          if (feeElement) {
            feeElement.scrollIntoView({ behavior: "smooth", block: "center" });
            setTimeout(() => {
              setHighlightedLawyerFeeId(newFeeId);
            }, 300);
          } else {
            // If element not found immediately, try again with longer delay
            setTimeout(() => {
              const retryElement =
                document.querySelector(`[data-lawyer-fee-id="${newFeeId}"]`) ||
                document.getElementById(`lawyer-fee-${newFeeId}`);
              if (retryElement) {
                retryElement.scrollIntoView({
                  behavior: "smooth",
                  block: "center",
                });
                setHighlightedLawyerFeeId(newFeeId);
              }
            }, 800);
          }
        }, 500);

        // Remove highlight after 5 seconds
        setTimeout(() => {
          setHighlightedLawyerFeeId(null);
        }, 5000);
      }
    } catch (error) {
      console.error("An error occurred in handleFeeSubmit:", error.message);
      alert(`حدث خطأ: ${error.message}`);
    } finally {
      if (typeof setIsSubmittingFee === "function") setIsSubmittingFee(false);
    }
  };

