  const handleActionSubmit = async (e) => {
    e.preventDefault();

    const currentUser = supabase.auth.user();
    if (!currentUser) {
      alert("يرجى تسجيل الدخول أولاً");
      return;
    }

    if (!caseDetails?.case_number) {
      alert("خطأ: رقم القضية غير متوفر");
      return;
    }

    // Get user data for the current user to attribute the action correctly
    let admin_id = currentUser.id;
    let user_id = currentUser.id;
    let lawyer_name = "مستخدم";

    try {
      // 1. Fetch current user's metadata to get their admin_user_id
      const { data: selfData, error: selfError } = await supabase
        .from("user_metadata")
        .select("admin_user_id, username, new_lawyer_id, user_id")
        .or(`user_id.eq.${currentUser.id},new_lawyer_id.eq.${currentUser.id}`)
        .limit(1);

      if (!selfError && selfData && selfData.length > 0) {
        const self = selfData[0];
        admin_id = self.admin_user_id || currentUser.id;
        user_id = self.new_lawyer_id || self.user_id || currentUser.id;
        lawyer_name = self.username || "مستخدم";

        // 2. If a specific lawyer was selected from the dropdown, try to fetch THEIR metadata
        if (selectedLawyer && selectedLawyer !== self.username) {
          const { data: targetData, error: targetError } = await supabase
            .from("user_metadata")
            .select("admin_user_id, username, new_lawyer_id")
            .eq("admin_user_id", admin_id)
            .eq("username", selectedLawyer)
            .limit(1);

          if (!targetError && targetData && targetData.length > 0) {
            const target = targetData[0];
            // We use the target's IDs for attribution
            user_id = target.new_lawyer_id || user_id;
            lawyer_name = target.username || lawyer_name;
          }
        }
      } else if (selfError) {
        console.error("Error fetching user metadata:", selfError.message);
      }
    } catch (err) {
      console.error("Exception in handleActionSubmit metadata fetch:", err);
    }

    // Default fallbacks are already set above

    // Fetch case_number_in_court from cases table (optional verification)
    const { data: caseData, error: caseError } = await supabase
      .from("cases")
      .select("case_number_in_court")
      .eq("case_number", caseDetails.case_number)
      .single();

    if (caseError) {
      console.error("Error fetching case data:", caseError.message);
      // We continue anyway if we have the case_number from details
    }

    const attachmentURL = popupActionData.attachment || null;

    const actionToInsert = {
      actiondate: popupActionData.actionDate,
      actiontype: popupActionData.actionType,
      actionstatus: popupActionData.actionStatus,
      actiondetails: popupActionData.actionDetails,
      case_number: caseDetails.case_number,
      attachment: attachmentURL,
      admin_id: admin_id,
      user_id: user_id,
      lawyer_name: lawyer_name,
    };

    try {
      // Insert action and get the inserted ID
      const { data: insertedData, error } = await supabase
        .from("actions")
        .insert([actionToInsert])
        .select();

      if (error) {
        console.error("Error inserting action data:", error.message);
        alert("حدث خطأ في إضافة الإجراء: " + error.message);
        return;
      }

      // Get the ID of the newly inserted action
      const newActionId = insertedData?.[0]?.id || insertedData?.id;

      // Reset form data
      setPopupActionData({
        actionDate: "",
        actionType: "",
        actionStatus: "",
        actionDetails: "",
        reminder: "",
        attachment: null,
      });
      setSelectedLawyer("");

      // Close popup
      handleCloseActionPopup();
      closeActionPopup();

      // Wait a moment for database to update
      await new Promise((resolve) => setTimeout(resolve, 500));

      // Trigger refresh in CaseActionsFeed
      setActionsRefreshTrigger((prev) => prev + 1);

      // Refresh parent's actions data as well
      await fetchActionData();

      // Switch to actions view
      setActiveView("actions");
      setHighlightedButton("actions");

      // Set the new action ID for highlighting
      if (newActionId) {
        // Wait for view to switch and DOM to update, then scroll and highlight
        setTimeout(() => {
          const findAndHighlight = () => {
            const actionElement = document.querySelector(
              `[data-action-id="${newActionId}"]`,
            );
            if (actionElement) {
              // Set highlight first
              setHighlightedActionId(newActionId);

              // Then scroll to the action
              setTimeout(() => {
                actionElement.scrollIntoView({
                  behavior: "smooth",
                  block: "center",
                });
              }, 100);

              return true;
            }
            return false;
          };

          // Try to find and highlight immediately
          if (!findAndHighlight()) {
            // If not found, try again after a short delay
            setTimeout(() => {
              if (!findAndHighlight()) {
                // Last attempt after longer delay
                setTimeout(() => {
                  findAndHighlight();
                }, 800);
              }
            }, 500);
          }
        }, 300);

        // Keep highlighting for 8 seconds (longer duration)
        setTimeout(() => {
          setHighlightedActionId(null);
        }, 8000);
      }
    } catch (error) {
      console.error("Error in handleActionSubmit:", error);

      let errorMessage = error.message || "حدث خطأ غير متوقع";

      // Check for network errors
      if (
        errorMessage.includes("Failed to fetch") ||
        errorMessage.includes("fetch")
      ) {
        errorMessage =
          "فشل الاتصال بالخادم. يرجى التحقق من اتصال الإنترنت أو التأكد من عدم وجود جدار ناري يمنع الاتصال، ثم حاول مرة أخرى.";
      }

      alert("حدث خطأ في إضافة الإجراء: " + errorMessage);
    }
  };

  const closeActionPopup = () => {
    setIsActionPopupOpen(false);
  };

  const handleCourtAttachmentChange = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    // Use selected folder or default to 'main'
    const folderName = selectedCourtFileFolder || "main";

    try {
      setCourtFile(file); // Update local state for UI feedback

      // Build path with timestamp to avoid collisions
      const fileName = `${Date.now()}_${file.name}`;
      const filePath = `${folderName}/${fileName}`;

      // 1) Upload to Supabase Storage (bucket "images")
      const { error: uploadError } = await supabase.storage
        .from("images")
        .upload(filePath, file);

      if (uploadError) {
        console.error("Error uploading court attachment:", uploadError.message);
        alert("خطأ في رفع الملف: " + uploadError.message);
        e.target.value = ""; // Reset input
        return;
      }

      // 2) Get Public URL
      const { publicURL } = supabase.storage
        .from("images")
        .getPublicUrl(filePath);

      setCourtFileUrl(publicURL);

      // 3) Insert into 'attachments' table so it appears in "Attached Files" tab
      const attachmentToInsert = {
        file_name: file.name,
        file_url: publicURL,
        case_number: caseDetails.case_number,
        created_at: new Date().toISOString(),
        folder_name: folderName,
      };

      const { error: insertError } = await supabase
        .from("attachments")
        .insert([attachmentToInsert]);

      if (insertError) {
        console.error(
          "Error inserting attachment record:",
          insertError.message,
        );
      } else {
        console.log("Court attachment recorded in attachments table.");
      }
    } catch (err) {
      console.error("Unexpected error in handleCourtAttachmentChange:", err);
      alert("حدث خطأ غير متوقع أثناء رفع الملف");
    } finally {
      e.target.value = ""; // Clear input to allow re-uploading same file if needed
    }
  };

  const handleSubmitCourtDecision = async (e) => {
    e.preventDefault();

    try {
      // Validate required fields
      if (
        !courtDecisionData.courtDetails ||
        courtDecisionData.courtDetails.trim() === ""
      ) {
        alert("يرجى إدخال تفاصيل الحكم");
        return;
      }

      if (!caseDetails?.case_number) {
        alert("خطأ: رقم القضية غير متوفر");
        console.error("Case number is missing");
        return;
      }

      // Get current user ID
      const user = supabase.auth.user();
      const currentUserId = user ? user.id : null;

      // Fetch user_metadata to determine if user is admin or lawyer
      // For lawyer: user_id (auth) = new_lawyer_id in user_metadata (lawyer's row)
      // For admin: user_id (auth) = user_id in user_metadata AND new_lawyer_id IS NULL (admin's own row)
      let userIdToSave = null;
      let userName = "مستخدم";
      if (currentUserId) {
        try {
          // First try to find by new_lawyer_id (for lawyer accounts)
          // This is unique to lawyers, so it won't match admin rows
          let { data: userMetadata, error: userError } = await supabase
            .from("user_metadata")
            .select("username, admin_user_id, new_lawyer_id, user_id")
            .eq("new_lawyer_id", currentUserId)
            .limit(1);

          // If not found as lawyer, try to find by user_id AND new_lawyer_id IS NULL (for admin accounts)
          // This ensures we get the admin's own row, not a lawyer row they created
          if (
            (userError || !userMetadata || userMetadata.length === 0) &&
            currentUserId
          ) {
            const { data: adminMetadata, error: adminError } = await supabase
              .from("user_metadata")
              .select("username, admin_user_id, new_lawyer_id, user_id")
              .eq("user_id", currentUserId)
              .is("new_lawyer_id", null)
              .limit(1);

            if (!adminError && adminMetadata && adminMetadata.length > 0) {
              userMetadata = adminMetadata;
              userError = null;
            }
          }

          if (!userError && userMetadata && userMetadata.length > 0) {
            const metadata = userMetadata[0];
            userName = metadata.username || "مستخدم";

            // Determine which ID to save:
            // If currentUserId matches new_lawyer_id in metadata, it's a lawyer -> save new_lawyer_id
            // If currentUserId matches user_id in metadata AND new_lawyer_id is null, it's an admin -> save admin_user_id
            if (metadata.new_lawyer_id === currentUserId) {
              // Lawyer account: save new_lawyer_id (the lawyer's ID)
              userIdToSave = metadata.new_lawyer_id;
            } else if (
              metadata.user_id === currentUserId &&
              !metadata.new_lawyer_id
            ) {
              // Admin account: save admin_user_id (the admin's ID)
              userIdToSave = metadata.admin_user_id || currentUserId;
            } else {
              // Fallback: use currentUserId
              userIdToSave = currentUserId;
            }
          }
        } catch (err) {
          console.error("Error fetching user metadata:", err);
        }
      }

      // Use the uploaded file URL if available
      const finalFileUrl = courtFileUrl || null;

      const courtDecisionToInsert = {
        details: courtDecisionData.courtDetails,
        appeal_date: courtDecisionData.courtDate || null,
        case_number: caseDetails.case_number,
        file_url: finalFileUrl,
        user_id: userIdToSave, // This will be admin_user_id or new_lawyer_id as text
        user_name: userName,
        created_at: new Date().toISOString(), // Set created_at timestamp
      };

      console.log("Inserting court decision:", courtDecisionToInsert);

      const { data, error } = await supabase
        .from("court")
        .upsert([courtDecisionToInsert])
        .select();

      if (error) {
        console.error("Error inserting court decision data:", error);
        alert(`خطأ في إضافة حكم المحكمة: ${error.message}`);
        return;
      }

      if (data && data.length > 0) {
        console.log("Court decision inserted successfully:", data[0]);

        // Show success message
        setCourtSuccessMessage(true);

        // Get the inserted court decision ID
        const newCourtId = data[0].id;

        // Reset form data
        setCourtDecisionData({
          courtDetails: "",
          courtDate: "",
        });
        setCourtFile(null);
        setCourtFileUrl(null);
        setSelectedCourtFileFolder("main");

        closeCourtDecisionPopup();

        // Refresh court decision data by fetching from database
        await fetchCourtData();

        // Switch to the correct view
        setActiveView("courtDecision");
        setHighlightedButton("courtDecision"); // Assuming this state controls the sidebar highlight

        // Wait a bit for the DOM to update, then scroll and highlight
        setTimeout(() => {
          const courtElement = document.querySelector(
            `[data-court-id="${newCourtId}"]`,
          );
          if (courtElement) {
            // Smooth scroll to the court decision
            courtElement.scrollIntoView({
              behavior: "smooth",
              block: "center",
            });

            // Set highlight after scroll starts
            setTimeout(() => {
              setHighlightedCourtId(newCourtId);
            }, 300);
          } else {
            // If element not found immediately, try again
            setTimeout(() => {
              const retryElement = document.querySelector(
                `[data-court-id="${newCourtId}"]`,
              );
              if (retryElement) {
                retryElement.scrollIntoView({
                  behavior: "smooth",
                  block: "center",
                });
                setHighlightedCourtId(newCourtId);
              }
            }, 500);
          }
        }, 300); // Increased delay slightly to ensure view switch happened

        // Remove highlighting after 5 seconds
        setTimeout(() => {
          setHighlightedCourtId(null);
        }, 5000);

        // Remove success message after 3 seconds
        setTimeout(() => {
          setCourtSuccessMessage(false);
        }, 3000);
      }
    } catch (error) {
      console.error("Error:", error);
      alert(`حدث خطأ غير متوقع: ${error.message}`);
    }
  };

