  const fetchCourtData = async () => {
    try {
      const { data, error } = await supabase
        .from("court")
        .select("*")
        .eq("case_number", caseDetails.case_number)
        .order("created_at", { ascending: false });

      if (error) {
        throw new Error("Error fetching court data");
      }

      // Enrich data with user info
      // court.user_id contains admin_user_id or new_lawyer_id (as text)
      // We need to match it against admin_user_id or new_lawyer_id in user_metadata
      if (data && data.length > 0) {
        const enrichedData = await Promise.all(
          data.map(async (courtItem) => {
            // If user_name is already present, use it
            if (courtItem.user_name) {
              return courtItem;
            }

            // Otherwise, fetch from user_metadata
            // court.user_id contains either admin_user_id or new_lawyer_id (as text)
            // Match it against new_lawyer_id first (lawyer case), then admin_user_id with new_lawyer_id IS NULL (admin case)
            if (courtItem.user_id) {
              try {
                // First try to find by new_lawyer_id (for lawyer accounts)
                // This is unique to lawyers, so it won't match admin rows
                let { data: userMetadata, error: userError } = await supabase
                  .from("user_metadata")
                  .select("username")
                  .eq("new_lawyer_id", courtItem.user_id)
                  .limit(1);

                // If not found, try admin_user_id AND new_lawyer_id IS NULL (for admin accounts)
                // This ensures we get the admin's own row, not a lawyer row they created
                if (userError || !userMetadata || userMetadata.length === 0) {
                  const { data: adminMetadata, error: adminError } =
                    await supabase
                      .from("user_metadata")
                      .select("username")
                      .eq("admin_user_id", courtItem.user_id)
                      .is("new_lawyer_id", null)
                      .limit(1);

                  if (
                    !adminError &&
                    adminMetadata &&
                    adminMetadata.length > 0
                  ) {
                    userMetadata = adminMetadata;
                    userError = null;
                  }
                }

                if (!userError && userMetadata && userMetadata.length > 0) {
                  return {
                    ...courtItem,
                    user_name: userMetadata[0].username || "مستخدم",
                  };
                }
              } catch (err) {
                console.error(
                  "Error fetching user metadata for court item:",
                  err,
                );
              }
            }

            return {
              ...courtItem,
              user_name: "مستخدم",
            };
          }),
        );

        setCourtTableData(enrichedData || []);
      } else {
        setCourtTableData([]);
      }

      setIsCourtTableDataLoaded(true);
    } catch (error) {
      console.error(error);
    }
  };

