  const fetchTasks = async () => {
    const effectiveCaseId = caseId || caseDetails?.id || caseNumber;
    if (!effectiveCaseId) return;

    setIsLoadingTasks(true); // Show the loading message
    try {
      // First, determine if identifier is a numeric ID or case_number
      const isNumericId = caseId && !isNaN(caseId);

      let tasksQuery = supabase
        .from("tasks")
        .select("*")
        .order("created_at", { ascending: false }); // Show newest tasks first

      if (isNumericId) {
        // Query by numeric case_id
        tasksQuery = tasksQuery.eq("case_id", parseInt(caseId));
      } else {
        // Query by case_number (task_case field)
        const caseNumToUse = caseNumber || caseDetails?.case_number || caseId;
        tasksQuery = tasksQuery.eq("task_case", caseNumToUse.toString());
      }

      if (caseDetails?.admin_id) {
        tasksQuery = tasksQuery.eq("admin_id", caseDetails.admin_id);
      }

      const { data, error } = await tasksQuery;

      if (error) {
        throw error;
      }

      // Enrich tasks with creator names and replies
      if (data && data.length > 0) {
        const taskIds = data.map((task) => task.id);

        // Fetch replies for all tasks from task_replies table (only if we have task IDs)
        let repliesData = [];
        let repliesError = null;

        if (taskIds.length > 0) {
          const repliesResult = await supabase
            .from("task_replies")
            .select("*")
            .in("task_id", taskIds)
            .order("created_at", { ascending: true }); // Oldest first

          repliesData = repliesResult.data || [];
          repliesError = repliesResult.error;
        }

        // Group replies by task_id
        const repliesByTask = {};
        if (!repliesError && repliesData) {
          repliesData.forEach((reply) => {
            if (!repliesByTask[reply.task_id]) {
              repliesByTask[reply.task_id] = [];
            }
            repliesByTask[reply.task_id].push(reply);
          });
        }

        const enrichedTasks = data.map((task) => ({
          ...task,
          creator_name:
            task.created_by_username || task.lawyer_related || "مستخدم",
          replies: repliesByTask[task.id] || [],
        }));

        setTasksData(enrichedTasks);
      } else {
        setTasksData([]);
      }
    } catch (error) {
      console.error("Error fetching tasks:", error);
      console.error("Error details:", error.message, error.code, error.details);
      alert(
        "حدث خطأ أثناء تحميل المهام: " + (error.message || "خطأ غير معروف"),
      );
    } finally {
      setIsLoadingTasks(false); // Hide the loading message
    }
  };

