                                    url = `https://calendar.google.com/calendar/render?action=TEMPLATE&text=جلسة: ${encodeURIComponent(sessionItem.sessionname || "جلسة")}&dates=${formattedDate.replace(/-/g, "")}/${formattedDate.replace(/-/g, "")}`;
