                                {caseDetails?.currency === "IQD" ? "دينار عراقي" : caseDetails?.currency === "USD" ? "دولار أمريكي" : caseDetails?.currency === "SAR" ? "ريال سعودي" : caseDetails?.currency || "ريال"}
